import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as d,a2 as s}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Safety/webdav-site-access.md","filePath":"fa/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),o={name:"fa/Safety/webdav-site-access.md"};function n(r,e,c,p,h,g){return l(),d("div",null,[...e[0]||(e[0]=[s('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>تنظیم WebDAV در Security Settings، سایت ImgBed شما را به‌عنوان WebDAV endpoint در دسترس قرار می‌دهد.</p><p>بعد از enable شدن، می‌توانید با Windows، macOS، mobile file managers یا هر WebDAV-compatible client، files داخل ImgBed را مثل یک remote folder browse، upload، delete و manage کنید.</p><p>این entry مربوط به WebDAV access خود سایت است و با WebDAV storage channel در Upload Settings فرق دارد. upload channel، files را در سرویس WebDAV شخص ثالث ذخیره می‌کند. این setting باعث می‌شود سایت ImgBed شما به clients، WebDAV access بدهد.</p><h2 id="کجا-configure-کنیم" tabindex="-1">کجا Configure کنیم <a class="header-anchor" href="#کجا-configure-کنیم" aria-label="Permalink to &quot;کجا Configure کنیم&quot;">​</a></h2><p>admin panel را باز کنید و بروید به:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>settings موجود:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="این-feature-چه-می‌کند" tabindex="-1">این Feature چه می‌کند <a class="header-anchor" href="#این-feature-چه-می‌کند" aria-label="Permalink to &quot;این Feature چه می‌کند&quot;">​</a></h2><p>پس از enable شدن WebDAV، ImgBed یک access URL ثابت ارائه می‌کند:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>برای اتصال به ImgBed file directory از همین URL استفاده کنید.</p><p>موارد استفاده مناسب:</p><ul><li>browse کردن مستقیم ImgBed files از file manager کامپیوتر.</li><li>drag کردن images داخل WebDAV folder برای upload.</li><li>organize کردن ImgBed folders از local file manager.</li><li>sync یا manage کردن images با WebDAV-compatible software.</li><li>دسترسی به ImgBed content بدون باز کردن admin panel.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>WebDAV endpoint را روشن می‌کند.</p><p>وقتی disabled باشد، clients نمی‌توانند از طریق WebDAV وصل شوند.</p><h3 id="username-و-password" tabindex="-1">Username و Password <a class="header-anchor" href="#username-و-password" aria-label="Permalink to &quot;Username و Password&quot;">​</a></h3><p>WebDAV clients هنگام اتصال از این credentials استفاده می‌کنند.</p><p>یک WebDAV username و password اختصاصی استفاده کنید. admin password یا upload password را دوباره استفاده نکنید.</p><p>اگر username یا password خالی باشد، WebDAV clients درست connect نمی‌شوند.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode مشخص می‌کند WebDAV clients هنگام خواندن images، کدام image URL را ترجیح دهند.</p><p>گزینه‌های رایج:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed بر اساس context انتخاب می‌کند. برای استفاده عادی recommended.</td></tr><tr><td>Original</td><td>original images را ترجیح می‌دهد.</td></tr><tr><td>Thumbnail</td><td>thumbnails را ترجیح می‌دهد. برای fast preview مفید است.</td></tr></tbody></table><p>اگر مطمئن نیستید، <code>Smart loading</code> را نگه دارید.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>default channel برای WebDAV uploads استفاده می‌شود.</p><p>وقتی از Windows یا client دیگر files را داخل WebDAV directory copy می‌کنید، ImgBed آن‌ها را از طریق selected default upload channel upload می‌کند.</p><p>اگر default channel انتخاب نشده باشد، browsing ممکن است کار کند، اما uploads fail می‌شوند.</p><h2 id="دسترسی-به-webdav-در-windows-11" tabindex="-1">دسترسی به WebDAV در Windows 11 <a class="header-anchor" href="#دسترسی-به-webdav-در-windows-11" aria-label="Permalink to &quot;دسترسی به WebDAV در Windows 11&quot;">​</a></h2><p>Windows 11 می‌تواند WebDAV را به‌عنوان network location اضافه کند.</p><ol><li><code>This PC</code> را باز کنید.</li><li><code>Add a network location</code> را انتخاب کنید.</li><li><code>https://your-domain.com/dav</code> را وارد کنید.</li><li>وقتی prompt آمد، WebDAV username و password را وارد کنید.</li><li>wizard را کامل کنید. سپس WebDAV directory در File Explorer باز می‌شود.</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>بعد از اضافه شدن، WebDAV directory در Windows File Explorer ظاهر می‌شود. می‌توانید مثل folder عادی files را open، copy و manage کنید.</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>پس از اتصال موفق WebDAV، معمولاً می‌توانید:</p><ul><li>files و folders را ببینید.</li><li>files upload کنید.</li><li>folders بسازید.</li><li>files یا folders را rename کنید.</li><li>files را move کنید.</li><li>files را delete کنید.</li></ul><p>WebDAV برای everyday access و مدیریت file در مقیاس کوچک مناسب است. برای moves بزرگ، bulk deletes یا organization پیچیده، admin panel را استفاده کنید.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>اتصال‌های موفق WebDAV در tab مربوط به WebDAV داخل Login Device Management هم ظاهر می‌شوند.</p><p>می‌توانید آنجا WebDAV clients را review کنید و در صورت نیاز old devices را force offline کنید.</p><p>اگر WebDAV username یا password را تغییر دهید، old clients باید دوباره sign in کنند.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-مدام-username-و-password-می‌خواهد" tabindex="-1">Windows مدام Username و Password می‌خواهد <a class="header-anchor" href="#windows-مدام-username-و-password-می‌خواهد" aria-label="Permalink to &quot;Windows مدام Username و Password می‌خواهد&quot;">​</a></h3><p>بررسی کنید:</p><ul><li>URL برابر <code>https://your-domain.com/dav</code> باشد.</li><li>username و password با WebDAV settings مطابقت داشته باشند.</li><li>WebDAV enabled باشد.</li><li>site از طریق HTTPS قابل دسترسی باشد.</li></ul><h3 id="browsing-کار-می‌کند،-اما-uploading-fail-می‌شود" tabindex="-1">Browsing کار می‌کند، اما Uploading fail می‌شود <a class="header-anchor" href="#browsing-کار-می‌کند،-اما-uploading-fail-می‌شود" aria-label="Permalink to &quot;Browsing کار می‌کند، اما Uploading fail می‌شود&quot;">​</a></h3><p><code>Default channel</code> را بررسی کنید.</p><p>WebDAV uploads به default upload channel نیاز دارد. اگر missing، disabled یا misconfigured باشد، uploads ممکن است fail شوند.</p><h3 id="access-speed-ناپایدار-است" tabindex="-1">Access Speed ناپایدار است <a class="header-anchor" href="#access-speed-ناپایدار-است" aria-label="Permalink to &quot;Access Speed ناپایدار است&quot;">​</a></h3><p>WebDAV performance به client، network، file count و default upload channel وابسته است.</p><p>اگر یک directory files زیادی دارد، آن‌ها را در folders organize کنید و تعداد زیادی file را در یک directory نگه ندارید.</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>برای WebDAV access از HTTPS استفاده کنید.</li><li>password قوی تنظیم کنید.</li><li>WebDAV password را با افراد غیرقابل‌اعتماد share نکنید.</li><li>وقتی استفاده نمی‌کنید WebDAV را off کنید.</li><li>در Login Device Management، WebDAV devices استفاده‌نشده را دوره‌ای clean up کنید.</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients از large-file chunking flow مربوط به browser upload page استفاده نمی‌کنند. برای files بزرگ‌تر از suggested limits زیر، از web upload page استفاده کنید.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(o,[["render",n]]);export{m as __pageData,f as default};
